mapper.select:
  	select * from (${customField}) t 
  	
  		
	  		
	  			
	  				`${key}` = #{value} AND
	  			
	  		
	  		
	  			
	  				
		  				
		  					`${item.data}` like BINARY CONCAT("%", #{fuzzyStr}, "%")
		  				
		  			
		  		
	  		
  		
  	
  	
        order by ${orderBy}
    
    
        limit #{start}, #{pageSize}
